const items = $input.all();

return items.map((item, index) => {
  const textArray = item.json.text || [];
  const fullTranscript = textArray
    .join(' ')
    .replace(/\s+/g, ' ')
    .replace(/&amp;#39;/g, "'")
    .replace(/&amp;quot;/g, '"')
    .trim();

  return {
    json: {
      ...item.json,
      transcript: fullTranscript
    },
    pairedItem: { item: index }
  };
});

let raw = $input.first().json.output || 
          $input.first().json.text || 
          $input.first().json.content;

if (Array.isArray(raw)) {
  raw = raw.map(b => b.text || '').join('');
}

raw = raw.trim();
const startIndex = raw.indexOf('[');
const endIndex = raw.lastIndexOf(']');

if (startIndex === -1 || endIndex === -1) {
  throw new Error('No JSON array found. Preview: ' + raw.substring(0, 100));
}

raw = raw.substring(startIndex, endIndex + 1);

let newsArray;
try {
  newsArray = JSON.parse(raw);
} catch(e) {
  try {
    let repaired = raw
      .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');
    newsArray = JSON.parse(repaired);
  } catch(e2) {
    throw new Error('Parse failed: ' + e.message);
  }
}

const inputItem = $input.first();

return newsArray.map((item) => ({
  json: {
    ...inputItem.json,
    title: item.title || '',
    summary: item.summary || '',
    body: item.body || '',
    telegram_body: item.telegram_body || '',
    tags: item.tags || '',
    image_prompt: item.image_prompt || '',
    publish_priority: item.publish_priority || 'normal'
  },
  pairedItem: { item: 0 }
}));

const items = $input.all();

const pending = items.filter(i => 
  i.json.status === 'pending' || i.json.status === 'N'
);

if (pending.length === 0) {
  return [{ json: { found: false } }];
}

const priority = { urgent: 1, normal: 2, evergreen: 3 };

const sorted = pending.sort((a, b) => {
  const pa = priority[a.json.publish_priority] || 99;
  const pb = priority[b.json.publish_priority] || 99;
  if (pa !== pb) return pa - pb;
  return new Date(a.json.publish_date) - new Date(b.json.publish_date);
});

const selected = sorted[0];

return [{
  json: {
    found: true,
    ...selected.json
  },
  pairedItem: { item: 0 }
}];

